// Some portions generated by Claude
package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.util.Map;
import java.util.Optional;
import java.util.Set;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Extension;
import org.eclipse.rdf4j.query.algebra.ExtensionElem;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.Str;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.eclipse.rdf4j.query.algebra.evaluation.optimizer.JoinFactorCostModel;
import org.eclipse.rdf4j.query.explanation.TelemetryMetricNames;
import org.junit.jupiter.api.Test;

/**
 * A join island that mixes triple patterns with an opaque factor (here a BIND / {@link Extension} whose expression only
 * uses variables bound by its own argument) must still be owned and reordered by the connected hypergraph planner.
 * Historically one opaque factor froze the whole island in written order.
 */
class LmdbOpaqueFactorJoinPlanningTest {

	private static final SimpleValueFactory VF = SimpleValueFactory.getInstance();
	private static final IRI FOLLOWS = VF.createIRI("http://example.com/social/follows");
	private static final IRI NAME = VF.createIRI("http://example.com/social/name");

	private static TupleExpr extensionIsland() {
		StatementPattern follows = new StatementPattern(new Var("person"), new Var("followsPred", FOLLOWS),
				new Var("x"));
		Extension bind = new Extension(follows, new ExtensionElem(new Str(new Var("x")), "xs"));
		StatementPattern selectiveName = new StatementPattern(new Var("x"), new Var("namePred", NAME),
				new Var("nameValue", VF.createLiteral("Name42")));
		return new Join(bind, selectiveName);
	}

	@Test
	void selfContainedExtensionFactorIslandIsOwnedByConnectedPlanner() {
		assertTrue(LmdbJoinIslandConnectivity.connectedJoinProviderCanOwn(extensionIsland()),
				"An island whose only non-pattern factor is a self-contained BIND should be reorderable");
	}

	@Test
	void legacyGateIsRestoredWhenOpaqueFactorsAreDisabled() {
		String previous = System.getProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY);
		System.setProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY, "false");
		try {
			assertFalse(LmdbJoinIslandConnectivity.connectedJoinProviderCanOwn(extensionIsland()),
					"Disabling opaque factors must restore the legacy written-order gate");
		} finally {
			if (previous == null) {
				System.clearProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY);
			} else {
				System.setProperty(LmdbJoinIslandConnectivity.OPAQUE_FACTORS_PROPERTY, previous);
			}
		}
	}

	@Test
	void extensionOutputSharedWithAnotherFactorKeepsIslandFrozen() {
		StatementPattern follows = new StatementPattern(new Var("person"), new Var("followsPred", FOLLOWS),
				new Var("x"));
		Extension bind = new Extension(follows, new ExtensionElem(new Str(new Var("x")), "xs"));
		StatementPattern consumesBindOutput = new StatementPattern(new Var("y"), new Var("namePred", NAME),
				new Var("xs"));
		assertFalse(LmdbJoinIslandConnectivity.connectedJoinProviderCanOwn(new Join(bind, consumesBindOutput)),
				"A BIND whose output is a runtime variable of another factor must not be reordered: written order "
						+ "joins on the shared name while a reordered Extension would overwrite it");
	}

	@Test
	void selectivePatternIsOrderedBeforeSelfContainedExtensionFactor() {
		TupleExpr island = extensionIsland();
		SelectiveNameStatistics statistics = new SelectiveNameStatistics();

		Optional<LmdbCascadesConnectedJoinPlanner.Plan> plan = LmdbCascadesConnectedJoinPlanner.plan(island, Set.of(),
				statistics, statistics);

		assertTrue(plan.isPresent(), "Expected the connected planner to own the BIND-bearing island");
		TupleExpr first = leftmostFactor(plan.get().tupleExpr());
		assertTrue(first instanceof StatementPattern,
				() -> "Expected the selective statement pattern to be seeded first: " + plan.get().tupleExpr());
		assertEquals(NAME, ((StatementPattern) first).getPredicateVar().getValue(),
				() -> "Expected the selective name lookup before the follows scan wrapped in BIND: "
						+ plan.get().tupleExpr());
	}

	private static TupleExpr leftmostFactor(TupleExpr tupleExpr) {
		TupleExpr current = tupleExpr;
		while (current instanceof Join join) {
			current = join.getLeftArg();
		}
		return current;
	}

	private static final class SelectiveNameStatistics extends EvaluationStatistics implements JoinFactorCostModel {

		@Override
		public double getCardinality(TupleExpr expr) {
			return 100_000.0d;
		}

		@Override
		public Optional<FactorCostEstimate> estimateFactorCost(TupleExpr factor, Set<String> currentlyBoundVars) {
			double rows;
			double workRows;
			if (factor instanceof StatementPattern pattern && NAME.equals(pattern.getPredicateVar().getValue())) {
				rows = 1.0d;
				workRows = 1.0d;
			} else if (currentlyBoundVars.contains("x")) {
				rows = 5.0d;
				workRows = 5.0d;
			} else {
				rows = 100_000.0d;
				workRows = 100_000.0d;
			}
			Map<String, String> stringMetrics = Map.of(
					TelemetryMetricNames.PLANNED_INDEX_ACCESS_MODE, "prefixScan",
					TelemetryMetricNames.PLANNED_INDEX_NAME, "spoc");
			Map<String, Double> doubleMetrics = Map.of(
					TelemetryMetricNames.PLANNED_ACCESS_ROWS, rows,
					TelemetryMetricNames.PLANNED_ACCESS_WORK_ROWS, workRows);
			return Optional.of(new FactorCostEstimate(rows, workRows, stringMetrics, doubleMetrics));
		}
	}
}
